        Iterator<String> iter = getRequiredOptions().iterator();
        StringBuilder buff = new StringBuilder("Missing required option");
        buff.append(getRequiredOptions().size() == 1 ? "" : "s");
        buff.append(": ");

        // loop through the required options
        while (iter.hasNext())
